## Common patterns

### Form integration with validation

Integrate RichTextInput with form libraries:

```jsx live-dev
const App = () => {
  const [content, setContent] = React.useState('');
  const [touched, setTouched] = React.useState(false);
  const [submitted, setSubmitted] = React.useState(false);

  const isEmpty = (html) => {
    const text = html.replace(/<[^>]*>/g, '').trim();
    return text.length === 0;
  };

  const error = (touched || submitted) && isEmpty(content)
    ? 'Content is required'
    : null;

  const handleSubmit = (event) => {
    event.preventDefault();
    setSubmitted(true);

    if (!isEmpty(content)) {
      console.log('Submitted:', content);
      alert('Form submitted successfully!');
    }
  };

  return (
    <form onSubmit={handleSubmit}>
      <Stack direction="column" gap="400">
        <FormField.Root isInvalid={!!error}>
          <FormField.Label isRequired>
            Article Content
          </FormField.Label>
          <FormField.Input>
            <RichTextInput
              value={content}
              onChange={setContent}
              onBlur={() => setTouched(true)}
              placeholder="Write your article..."
              isInvalid={!!error}
            />
          </FormField.Input>
          <FormField.Description>
            Minimum 10 characters required
          </FormField.Description>
          {error && (
            <FormField.Error>{error}</FormField.Error>
          )}
        </FormField.Root>
        <Button type="submit">Submit Article</Button>
      </Stack>
    </form>
  );
};
```

### Content length validation

Validate content length by parsing HTML:

```jsx live-dev
const App = () => {
  const [content, setContent] = React.useState('');

  const getTextLength = (html) => {
    return html.replace(/<[^>]*>/g, '').trim().length;
  };

  const textLength = getTextLength(content);
  const minLength = 10;
  const maxLength = 500;
  const isValid = textLength >= minLength && textLength <= maxLength;

  return (
    <Stack direction="column" gap="400">
      <FormField.Root isInvalid={!isValid && textLength > 0}>
        <FormField.Label>Post Content</FormField.Label>
        <FormField.Input>
          <RichTextInput
            value={content}
            onChange={setContent}
            placeholder="Write your post..."
            isInvalid={!isValid && textLength > 0}
          />
        </FormField.Input>
        <Stack direction="row" justifyContent="space-between">
          <FormField.Description>
            {textLength < minLength && textLength > 0
              ? `${minLength - textLength} more characters needed`
              : textLength > maxLength
              ? `${textLength - maxLength} characters over limit`
              : 'Character count within range'}
          </FormField.Description>
          <Text
            fontSize="350"
            color={isValid || textLength === 0 ? 'neutral.11' : 'critical.11'}
          >
            {textLength} / {maxLength}
          </Text>
        </Stack>
      </FormField.Root>
    </Stack>
  );
};
```

## Testing your implementation

These examples demonstrate how to test your implementation when using RichTextInput in your application. As the component's internal functionality is already tested by Nimbus, these patterns help you verify your integration and application-specific logic.

### Basic Usage Tests

Test basic RichTextInput rendering and HTML value handling

```tsx
import { describe, it, expect } from "vitest";
import { render, screen, waitFor } from "@testing-library/react";
import { useState } from "react";
import { RichTextInput, NimbusProvider } from "@commercetools/nimbus";

describe("RichTextInput - Basic usage", () => {
  it("renders with default HTML value", () => {
    const initialContent = "<p>Welcome to the <strong>editor</strong>!</p>";

    render(
      <NimbusProvider>
        <RichTextInput defaultValue={initialContent} />
      </NimbusProvider>
    );

    const editor = screen.getByRole("textbox");
    expect(editor).toHaveTextContent("Welcome to the editor!");
    expect(editor.querySelector("strong")).toHaveTextContent("editor");
  });

  it("displays placeholder when empty", async () => {
    render(
      <NimbusProvider>
        <RichTextInput placeholder="Start typing..." />
      </NimbusProvider>
    );

    const editor = screen.getByRole("textbox");
    // Slate.js uses data-slate-placeholder for empty state
    await waitFor(() => {
      const placeholder = editor.querySelector("[data-slate-placeholder]");
      expect(placeholder).toBeInTheDocument();
    });
  });
});
```

### Controlled vs Uncontrolled Tests

Test controlled and uncontrolled component patterns

```tsx
import { describe, it, expect } from "vitest";
import { render, screen, waitFor } from "@testing-library/react";
import { useState } from "react";
import { RichTextInput, NimbusProvider } from "@commercetools/nimbus";

describe("RichTextInput - Controlled vs Uncontrolled", () => {
  it("works in uncontrolled mode with defaultValue", () => {
    render(
      <NimbusProvider>
        <RichTextInput defaultValue="<p>Uncontrolled content</p>" />
      </NimbusProvider>
    );

    const editor = screen.getByRole("textbox");
    expect(editor).toHaveTextContent("Uncontrolled content");
  });

  it("works in controlled mode with value and onChange", () => {
    const TestComponent = () => {
      const [value, setValue] = useState("<p>Controlled content</p>");
      return <RichTextInput value={value} onChange={setValue} />;
    };

    render(
      <NimbusProvider>
        <TestComponent />
      </NimbusProvider>
    );

    const editor = screen.getByRole("textbox");
    expect(editor).toHaveTextContent("Controlled content");
  });
});
```

